import { Navigation } from '@/components/navigation';
import { LogList } from '@/components/log-list';
import connectDB from '@/lib/db';
import SiteSetting from '@/models/SiteSetting';

export const revalidate = 0; // force dynamic so it fetches updated bg image

export default async function LogPage() {
  let bgUrl = '';
  try {
    await connectDB();
    const setting = await SiteSetting.findOne();
    bgUrl = setting?.logBgUrl || '';
  } catch (error) {
    console.error('Failed to connect to database in LogPage:', error);
  }

  return (
    <div 
      className="min-h-screen bg-transparent relative"
      style={{
        backgroundImage: bgUrl ? `url(${bgUrl})` : 'none',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundAttachment: 'fixed',
      }}
    >
      {/* Optional dark overlay if you want the background to be slightly darker behind everything */}
      {bgUrl && <div className="absolute inset-0 bg-background/40 z-0 pointer-events-none" />}
      
      <div className="relative z-10 w-full">
        <Navigation />
        <main className="w-[95%] md:w-[60%] mx-auto py-8">
          <LogList />
        </main>
      </div>
    </div>
  );
}
