import mongoose from 'mongoose';

const SiteSettingSchema = new mongoose.Schema(
  {
    bgmUrl: {
      type: String,
      default: '/music/bgm.mp3',
    },
    logBgUrl: {
      type: String,
      default: '',
    },
    // 나중에 다른 전역 설정을 넣기 위함
  },
  {
    timestamps: true,
  }
);

export default mongoose.models.SiteSetting || mongoose.model('SiteSetting', SiteSettingSchema);
